/**
 * Data assembly for the photographer pages ("Darkroom" design).
 *
 * Reads live rows from D1 when available and enriches them with true image
 * dimensions from lib/data/photoManifest.json (generated by
 * scripts/build-photo-manifest.mjs — EXIF-orientation corrected, plus
 * white-matte detection for the squares wall).
 *
 * When D1 is not reachable (local `next dev`, build machines) the manifest
 * itself is used as the row source, so pages always render with real content.
 */

import manifest from './photoManifest.json'
import { normalizePhotoKey, toPublicPath } from '../photoUtils'

const CAT_ZH = {
  HK: '香港',
  City: '城市',
  Travel: '旅途',
  Portrait: '人像',
  Emotion: '情绪',
  Lover: '恋人',
  Wedding: '婚礼',
  Nature: '自然',
  Ghibli: '吉卜力',
  Phone: '随手',
}

// INDEX overlay order — people first (portraits are the main business).
const CAT_ORDER = ['Portrait', 'Emotion', 'Lover', 'Wedding', 'HK', 'City', 'Travel', 'Nature', 'Ghibli', 'Phone']

// Hand-picked hero images — the photographer's own banner curation (1–5).
// Shown as one full-bleed band; `fw` is the flex weight (≈ visible aspect
// ratio) so portraits stay nearly uncropped while the landscape frame (4)
// takes a center crop and the biggest parallax travel.
const HERO_PANELS = [
  { p: '/photography/banner/2.jpg', w: 1344, h: 1680, fw: 0.8 },
  { p: '/photography/banner/1.jpg', w: 1343, h: 1680, fw: 0.8 },
  { p: '/photography/banner/3.jpg', w: 1344, h: 1680, fw: 0.8 },
  { p: '/photography/banner/5.jpg', w: 1344, h: 1680, fw: 0.8 },
  { p: '/photography/banner/4.jpg', w: 1640, h: 1093, fw: 0.95 },
]

/**
 * Frames curated by eye from contact sheets of every category's top photos.
 * Resolved by filename so upstream re-sorting can't break them; anything
 * missing falls back to the top of its category pool (white mattes excluded —
 * those belong to the wall).
 */
