const EPI_PICK = ['Portrait', '0E6305BE-35AD-4370-B512-BEE2AE5827D4.webp'] // writing by the rain window

const dimsByPath = new Map(manifest.photos.map(ph => [ph.path, ph]))

function toEntry(row) {
  const key = normalizePhotoKey(row.path, row.category, row.filename)
  const p = toPublicPath(key)
  const dims = dimsByPath.get(p)
  return {
    p,
    w: dims ? dims.w : null,
    h: dims ? dims.h : null,
    cat: row.category,
    matte: dims ? !!dims.matte : false,
  }
}

async function fetchRows(db) {
  if (db) {
    try {
      const { results } = await db.prepare(
        'SELECT category, filename, path, sort_order, created_at FROM photos'
      ).all()
      if (results && results.length > 0) return results
    } catch (e) {
      console.error('darkroom: D1 query failed, falling back to manifest:', e.message)
    }
  }
  return manifest.photos
}

/** Round-robin interleave grouped lists so the wall mixes categories. */
function interleave(groups) {
  const out = []
  const lists = groups.filter(g => g.length > 0)
  const total = lists.reduce((s, l) => s + l.length, 0)
  let i = 0
  while (out.length < total) {
    for (const list of lists) {
      if (list[i]) out.push(list[i])
    }
    i++
  }
  return out
}

function buildPools(rows) {
  const pools = new Map()
  for (const row of rows) {
    const cat = typeof row.category === 'string' ? row.category.trim() : ''
    if (!cat) continue
    if (!pools.has(cat)) pools.set(cat, [])
    pools.get(cat).push(row)
  }
  for (const list of pools.values()) {
    list.sort((a, b) => {
      const sa = a.sort_order ?? Number.MAX_SAFE_INTEGER
      const sb = b.sort_order ?? Number.MAX_SAFE_INTEGER
      if (sa !== sb) return sa - sb
      return String(a.filename).localeCompare(String(b.filename))
    })
  }
  return pools
}

export async function getDarkroomHomeData(db) {
  const rows = await fetchRows(db)
  const pools = buildPools(rows)

  const findByName = (cat, filename) => {
    const row = (pools.get(cat) || []).find(r => r.filename === filename)
    return row ? toEntry(row) : null
  }

  const resolvePicks = picks => {
    const found = picks.map(([cat, f]) => findByName(cat, f)).filter(Boolean)
    return { found, missing: picks.length - found.length }
  }

  /** Top of a category pool, curated picks and white mattes excluded. */
  const takeClean = (cat, n, used) =>
    (pools.get(cat) || [])
      .map(toEntry)
      .filter(e => !e.matte && !(used && used.has(e.p)))
      .slice(0, n)

  const usedPaths = list => new Set(list.map(e => e.p))

  // ——— CH.01 PEOPLE — two auto-advancing film rows ———
  const aRes = resolvePicks(STRIP_A_PICKS)
  const stripA = aRes.found
  if (aRes.missing > 0) stripA.push(...takeClean('Portrait', aRes.missing, usedPaths(stripA)))

  const bRes = resolvePicks(STRIP_B_PICKS)
  const stripB = bRes.found
  if (bRes.missing > 0) {
    const used = usedPaths([...stripA, ...stripB])
    stripB.push(...takeClean('Emotion', bRes.missing, used))
  }

  // ——— CH.02 CITY — three drifting layers ———
  const cityRows = CITY_ROW_PICKS.map(rowPicks => {
    const res = resolvePicks(rowPicks)
    const row = res.found
    if (res.missing > 0) row.push(...takeClean('City', res.missing, usedPaths(row)))
    return row
  })

  // ——— CH.03 WALL — every square print with a baked-in white matte ———
  const mattesByCat = new Map()
  for (const ph of manifest.photos) {
    if (!ph.square || !ph.matte) continue
    if (!mattesByCat.has(ph.category)) mattesByCat.set(ph.category, [])
    mattesByCat.get(ph.category).push({ p: ph.path, w: ph.w, h: ph.h, cat: ph.category })
  }
  const wall = interleave([...mattesByCat.values()])

  // ——— epilogue: the writing print on the gold band ———
  const epi = findByName(...EPI_PICK) || takeClean('Portrait', 1)[0] || HERO_PANELS[0]

  // ——— INDEX overlay ———
  const knownOrder = CAT_ORDER.filter(c => pools.has(c))
  const extras = [...pools.keys()].filter(c => !CAT_ORDER.includes(c)).sort()
  const cats = [...knownOrder, ...extras].map(name => ({
    name,
    zh: CAT_ZH[name] || name,
    count: (pools.get(name) || []).length,
    href: `/photographer/${name.toLowerCase()}`,
    thumbs: (pools.get(name) || []).slice(0, 4).map(r => toEntry(r).p),
  }))

  const counts = {
    total: rows.length,
    people: ['Portrait', 'Emotion', 'Lover', 'Wedding']
      .reduce((s, c) => s + (pools.get(c) || []).length, 0),
    cats: cats.length,
    wall: wall.length,
  }

  return { hero: HERO_PANELS, stripA, stripB, cityRows, wall, epi, cats, counts }
}

/**
 * Category gallery ("roll scan") data. Photos keep their native aspect
 * ratios and are chunked into justified rows (equal height per row via the
 * flex-grow = aspect-ratio trick), then grouped into film rolls.
 */
const ROW_TARGETS = [3.4, 4.3, 2.9, 3.8, 4.6, 3.1]
const ROLL_SIZES = [3, 4, 3, 4]

function chunkJustified(entries) {
  const rows = []
  let items = []
  let sum = 0
  let ti = 0
  for (const e of entries) {
    const ar = e.w && e.h ? e.w / e.h : 1.5
    items.push({ ...e, ar: Math.round(ar * 1000) / 1000 })
    sum += ar
    if (sum >= ROW_TARGETS[ti % ROW_TARGETS.length] || items.length >= 5) {
      rows.push({ items, target: sum, partial: false })
      items = []
      sum = 0
      ti++
    }
  }
  if (items.length) {
    // Don't stretch a thin trailing row to full width — pad with a spacer.
    const target = ROW_TARGETS[ti % ROW_TARGETS.length]
    rows.push({ items, target: Math.max(sum, Math.min(target, sum * 1.9)), partial: sum < target * 0.72 })
  }
  return rows
}

export async function getDarkroomGalleryData(db, slug) {
  const rows = await fetchRows(db)
  const pools = buildPools(rows)

  const name = [...pools.keys()].find(c => c.toLowerCase() === String(slug).toLowerCase())
  if (!name) return null

  const entries = pools.get(name).map((r, i) => ({ ...toEntry(r), n: i + 1 }))
  const lead = entries[0] || null
  const justified = chunkJustified(entries.slice(1))

  const rolls = []
  let ri = 0
  let cursor = 0
  while (cursor < justified.length) {
    const take = ROLL_SIZES[ri % ROLL_SIZES.length]
    rolls.push(justified.slice(cursor, cursor + take))
    cursor += take
    ri++
  }

  const knownOrder = CAT_ORDER.filter(c => pools.has(c))
  const extras = [...pools.keys()].filter(c => !CAT_ORDER.includes(c)).sort()
  const orderedCats = [...knownOrder, ...extras]
  const idx = orderedCats.indexOf(name)
  const catInfo = c => ({
    name: c,
    zh: CAT_ZH[c] || c,
    count: (pools.get(c) || []).length,
    href: `/photographer/${c.toLowerCase()}`,
  })

  return {
    name,
    zh: CAT_ZH[name] || name,
    count: entries.length,
    lead,
    rolls,
    cats: orderedCats.map(catInfo),
    prev: catInfo(orderedCats[(idx - 1 + orderedCats.length) % orderedCats.length]),
    next: catInfo(orderedCats[(idx + 1) % orderedCats.length]),
  }
}
